// Generated by Spec-to-RTL pipeline: grammar -> IR -> RTL
// normalized from unstructured text

module text_counter (
    input clk,
    input rst_n,
    input enable,
    output [7:0] count
);

    reg [7:0] count_r;
    assign count = count_r;

    always @(posedge clk or posedge rst_n) begin
        if (rst_n) begin
            count <= 0;
        end else begin
            count <= count;
            if (enable) begin
                count <= count + 1;
            end
        end
    end

endmodule
